create table expense_types (
    id          number generated by default as identity not null enable,
    code        varchar2(30 byte),
    name_en     varchar2(200 byte),
    name_ar     varchar2(200 byte),
    description varchar2(500 byte),
    parent_id   number,
    is_active   char(1 byte) default 'Y',
    created_at  date default sysdate,
    created_by  varchar2(100 byte),
    updated_at  date,
    updated_by  varchar2(100 byte)
);

alter table expense_types add primary key ( id )
    using index enable;

alter table expense_types add unique ( code )
    using index enable;

